"use client";

import React, { useMemo, useState } from "react";
import { Heart, Maximize2, Share2 } from "lucide-react";

export default function ProductGallery({ product }) {
  const images = useMemo(() => {
    const allImages = [product?.thumbnail, ...(product?.images || [])].filter(
      Boolean,
    );
    const uniqueImages = [...new Set(allImages)];

    if (uniqueImages.length > 0) {
      return uniqueImages.map(
        (image) => `http://localhost:5000/product/${image}`,
      );
    }

    return ["/headPhone.png", "/hero.png", "/dealsoftheday/mainImage.png"];
  }, [product]);

  const [activeImage, setActiveImage] = useState(images[0]);

  return (
    <div className="lg:sticky lg:top-6">
      <div className="relative overflow-hidden rounded-lg border border-slate-200 bg-white shadow-sm">
        <div className="absolute left-4 top-4 z-10 rounded-md bg-green-800 px-3 py-1.5 text-xs font-extrabold text-white shadow-sm">
          Best Deal
        </div>

        <div className="absolute right-4 top-4 z-10 flex gap-2">
          <button className="grid h-10 w-10 place-items-center rounded-full bg-white text-slate-600 shadow-sm ring-1 ring-slate-200 transition hover:text-[#01A49E]">
            <Heart size={18} />
          </button>
          <button className="grid h-10 w-10 place-items-center rounded-full bg-white text-slate-600 shadow-sm ring-1 ring-slate-200 transition hover:text-[#01A49E]">
            <Share2 size={18} />
          </button>
        </div>

        <div className="flex aspect-square items-center justify-center bg-gradient-to-b p-4">
          <div className="w-fit px-4">
            <div className=" w-15  ">
              {images.map((image, index) => (
                <button
                  key={image}
                  type="button"
                  onClick={() => setActiveImage(image)}
                  className={`aspect-square overflow-hidden rounded-md border bg-white p-2 py- mb-2  shadow-sm transition-all duration-20 ${
                    activeImage === image
                      ? "border"
                      : "border-slate-200"
                  }`}
                >
                  <img
                    src={image}
                    alt={`Product thumbnail ${index + 1}`}
                    className="h-full w-full  object-contain"
                  />
                </button>
              ))}
            </div>
          </div>
          <div className="flex-1">
            <img
              src={activeImage}
              alt={product?.name || "Product image"}
              className="h-full w-full object-contain"
            />
          </div>
        </div>
      </div>
    </div>
  );
}
